generated_oml:
// Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor on the permanent‑magnet synchronous motor"
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorPositionSensor : DTDFVocab:SensingComponent [
    base:desc "Position encoder directly on the motor"
    DTDFVocab:producedData MotorPositionDataTransmitted
]

instance GearboxPositionSensor : DTDFVocab:SensingComponent [
    base:desc "Position encoder behind the gearbox"
    DTDFVocab:producedData GearboxPositionDataTransmitted
]

// Data transmitted from sensors (physical‑to‑virtual interaction)
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorPositionSensor
]

instance GearboxPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxPositionSensor
]

// Data objects (data layer)
instance CurrentMeasuredData : DTDFVocab:Data [
    base:desc "Measured motor current data from the motor current sensor"
    DTDFVocab:inputTo MQTTBrokerEnabler
    DTDFVocab:fromData MotorCurrentDataTransmitted
]

instance MotorPositionMeasuredData : DTDFVocab:Data [
    base:desc "Measured motor position data from the position encoder on the motor"
    DTDFVocab:inputTo MQTTBrokerEnabler
    DTDFVocab:fromData MotorPositionDataTransmitted
]

instance GearboxPositionMeasuredData : DTDFVocab:Data [
    base:desc "Measured gearbox position data from the encoder behind the gearbox"
    DTDFVocab:inputTo MQTTBrokerEnabler
    DTDFVocab:fromData GearboxPositionDataTransmitted
]

// Derived data produced by processing component
instance TorqueComputedData : DTDFVocab:Data [
    base:desc "Computed torque derived from current and position data"
    DTDFVocab:inputTo DataProcessingEnabler
    DTDFVocab:fromData CurrentMeasuredData, MotorPositionMeasuredData
]

instance AngularVelocityComputedData : DTDFVocab:Data [
    base:desc "Computed angular velocity derived from position data"
    DTDFVocab:inputTo DataProcessingEnabler
    DTDFVocab:fromData MotorPositionMeasuredData
]

instance AccelerationComputedData : DTDFVocab:Data [
    base:desc "Computed angular acceleration derived from position data"
    DTDFVocab:inputTo DataProcessingEnabler
    DTDFVocab:fromData MotorPositionMeasuredData
]

// Friction model parameter data (for model refinement)
instance FrictionModelParameterData : DTDFVocab:Data [
    base:desc "Updated friction model parameters derived from data refinement"
    DTDFVocab:inputTo DataProcessingEnabler
    DTDFVocab:fromData CurrentMeasuredData, MotorPositionMeasuredData
]

// Enablers (tools and software)
instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker for real‑time data streaming"
    DTDFVocab:enables DataStreamingService
]

instance SysMLStructEnabler : DTDFVocab:Enabler [
    base:desc "SysML for structural and behavioral modeling of the drive train"
    DTDFVocab:enables ModelAnalysisService
]

instance MATLABSimulinkEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink for executable simulation of motor, gearwheel, and gearbox"
    DTDFVocab:enables SimulationExecutionService
]

instance DataProcessingEnabler : DTDFVocab:Enabler [
    base:desc "Processing component for data calculation and friction model refinement"
    DTDFVocab:enables ModelRefinementService
]

instance AASIntegrationEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell integration for semantic linking"
    DTDFVocab:enables SemanticLinkService
]

instance DashboardEnabler : DTDFVocab:Enabler [
    base:desc "Dashboard for data visualization and operator insight"
    DTDFVocab:enables DataVisualizationService
]

// Services
instance DataStreamingService : DTDFVocab:Service [
    base:desc "Real‑time identification and continuous refinement of joint friction models"
    DTDFVocab:provides RealTimeDataInsight
]

instance SimulationExecutionService : DTDFVocab:Service [
    base:desc "Execution of executable Simulink models for motor, gearwheel, and gearbox"
    DTDFVocab:provides SimulationDataInsight
]

instance ModelAnalysisService : DTDFVocab:Service [
    base:desc "Comparison of simulated and measured behavior for model validation"
    DTDFVocab:provides ModelComparisonInsight
]

instance SemanticLinkService : DTDFVocab:Service [
    base:desc "Semantic linking between physical assets and digital representations via AAS"
    DTDFVocab:provides SemanticIntegrationInsight
]

instance ModelRefinementService : DTDFVocab:Service [
    base:desc "Real‑time refinement of joint friction models (white‑box and black‑box)"
    DTDFVocab:provides FrictionModelUpdateInsight
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Visualization of data traces and provision of improved motion‑accuracy information"
    DTDFVocab:provides DashboardVisualizationInsight, MotionAccuracyImprovementAction, MaintenanceDecisionInsight
]

// Insights and Actions
instance RealTimeDataInsight : DTDFVocab:Insight [
    base:desc "Live sensor data streaming insight for real‑time monitoring"
]

instance SimulationDataInsight : DTDFVocab:Insight [
    base:desc "Simulated behavior insight from executable models"
]

instance ModelComparisonInsight : DTDFVocab:Insight [
    base:desc "Insight from comparison of simulated and measured joint behavior"
]

instance SemanticIntegrationInsight : DTDFVocab:Insight [
    base:desc "Insight from semantic linking between physical assets and digital twin"
]

instance FrictionModelUpdateInsight : DTDFVocab:Insight [
    base:desc "Insight on friction model parameter updates during operation"
]

instance DashboardVisualizationInsight : DTDFVocab:Insight [
    base:desc "Insight from visualized data traces in the dashboard"
]

instance MaintenanceDecisionInsight : DTDFVocab:Insight [
    base:desc "Informed maintenance decision insight derived from data analysis"
]

instance MotionAccuracyImprovementAction : DTDFVocab:Action [
    base:desc "Action to improve robot motion accuracy based on updated friction models"
    DTDFVocab:IsAutomatic false
]

// Models
instance MotorModel : DTDFVocab:Model [
    base:desc "SysML component‑connector model of the permanent‑magnet synchronous motor"
    DTDFVocab:inputTo SysMLStructEnabler, MATLABSimulinkEnabler
]

instance GearwheelModel : DTDFVocab:Model [
    base:desc "SysML component‑connector model of the first gearwheel gearbox"
    DTDFVocab:inputTo SysMLStructEnabler, MATLABSimulinkEnabler
]

instance GearboxModel : DTDFVocab:Model [
    base:desc "SysML component‑connector model of the cycloidal gearbox in the drive train"
    DTDFVocab:inputTo SysMLStructEnabler, MATLABSimulinkEnabler
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time data processing synchronized with the robot’s sampling rate; the digital shadow ingests MQTT messages at the same rate as the sensor output and executes simulation models in steps compatible with real‑time operation."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "Consists of the asset (first robot axis), the engineering model (SysML), the simulation models (Simulink), the processing component that generates data traces, the AAS linking mechanism, and the dashboard interface, all interconnected via MQTT and AAS interfaces."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Covers the ideal design phase (friction‑free simulation model), the manufactured phase (sensor data from the physical robot), and the operated phase (live data integration and continuous model refinement during operation)."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Every data point is traceable back to its source and the processing model; both analytical (white‑box) and data‑driven (black‑box) friction models are used; continuous model identification is validated by comparing simulated outputs with measured data; adherence to MBSE principles ensures engineering model fidelity."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "MQTT broker mediates data flow from PT sensors to DT; data is linked to the AAS representation; the dashboard accesses the data via HTTP/WebSocket interfaces."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "SysML for MBSE, Asset Administration Shell (AAS) standard for semantic linking, MQTT messaging protocol, and MATLAB/Simulink for simulation."
]
